INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2177354','Парова машина','Українська народна пісня. Виконує: ДримбаДaДзига','uk','ukraine_before_1917',NULL,NULL,NULL,'Виконує: ДРИМБА ДА ДЗИГА Альбом:','Була в мене парова машина,
А я її продала.

А за тії гроші музики хороші
Найняла, найняла.

Ой, музики мої, ви заграйте мені
Коваля, коваля.

А коваль коваля через ножку валя
Раз у раз, раз у раз.

Була в мене сіренька хустина,
Та я її продала.

А за тії гроші музики хороші
Найняла, найняла.

Було в мене червоне намисто,
Та я його продала.

А за тії гроші музики хороші
Найняла, найняла.

Ой, музики мої, ви заграйте мені
Коваля, коваля.

А коваль коваля через ножку валя
Раз у раз, раз у раз','["pisni.org.ua", "cat:narodni", "cat:zhartivlyvi", "Народні пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2177354'), datetime('now')),datetime('now'));
