INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_217716','Мені однаково чи буду','Музика: Микола Лисенко Слова: Тарас Шевченко. Виконує: Іван Козловський, Леонід Мазур','uk','ukraine_before_1917',NULL,'1847','Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Тарас Шевченко. В казематі. ІІІ [Між 17 квітня і 19 травня 1847, С.-Петербург] Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Голосна та Правдива як Господа слово. Присплять лукаві і в огні Її окраденую збудять. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Св. Микола 19.12 – Народний речник перед Богом і Прадід. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Стежки до листків про Українські традиції. Джерела в мереживі: ПОЕТИКА - http://poetry.uazone.net/kobzar/meni_odnakovo.html УКР.ЦЕНТР http://www.ubnews.co.uk/music/narodna.htm (були деньки:) — Різні Виконавці - http://www.ubnews.co.uk/music/rizni.htm (були деньки:) http://ukrsong.narod.ru/htmls/kozlov.html; http://leonpar.narod.ru/Kopilka.HTML','Мені однаково чи буду
Я жить в Україні чи ні
Чи хто згадає чи забуде
Мене в снігу на чужині
Однаковісінько мені

В неволі виріс меж чужими
І не оплаканий своїми
В неволі плачучи умру
І все з собою заберу
Малого сліду не покину
На нашій славній Україні
На нашій не своїй землі

І не пом''яне Батько з Сином
Не скаже Синові молись
Молися Сину за Вкраїну
Його замучили колись

Мені однаково чи буде
Той син молитися чи ні...

Та не однаково мені
Як Україну злії люде
Присплять лукаві і в огні
Її окраденую збудять...

Ох не однаково мені','["pisni.org.ua", "cat:emigration", "cat:istorychni", "cat:nostalgia", "cat:philosophic", "cat:pro-batkiv", "Пісні про еміґрацію", "Історичні пісні", "Пісні з ностальгічними мотивами", "Філософські пісні", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_217716'), datetime('now')),datetime('now'));
