INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2178818','Арфами, арфами','Музика: Леся Тельнюк Слова: Павло Тичина. Виконує: Сестри Тельнюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Арфами, арфами -
Золотими, голосними
Обізвалися гаї.
Самодзвонними:
Йде весна
Запашна,
Квітами-перлами
Закосичена.
Думами, думами -
Наче море кораблями,
Переповнилась блакить
Ніжнотонними:
Буде бій
Вогневий!
Сміх буде, плач буде
Перламутровий...
Стану я, гляну я -
Скрізь поточки,
Як дзвіночки, жайворон,
Як золотий
З переливами:
Йде весна
Запашна,
Квітами-перлами
Закосичена.
Любая, милая, -
Чи засмучена ти ходиш,
Чи налита щастям вкрай.
Там за нивами:
Ой одкрий
Колос вій!
Сміх буде, плач буде
Перламутровий...','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2178818'), datetime('now')),datetime('now'));
