INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2179694','Ой, Купало-Розкупало','Українська народна пісня. Виконує: Марта Шпак, Сергій Гера, Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, Купало-Розкупало
