INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_217993','Олімпійський гімн українських вболівальників','Музика: Тетяна Шамшетдінова Слова: Олександр Положинський','uk','ukraine_1991',NULL,NULL,NULL,'Виконують: Наталія Могілевська, Андрій Кузьменко (Скрябін), Сашко Положинський (Тартак), Фагот (ТНМК).','Яке гаряче цього року літо,
Який солоний вітер з-за морів,
Не спить стара вершина цього світу
І вже чекає на нових царів.
Хтось завзято грає, інші знають міру,
Хтось перемагає, хтось у нього вірить.

Приспів:
Україно вперед, Україно давай,
Україно вперед, перемагай!

Така вже доля - плакати, радіти,
Здобути все або забути все,
Бо золотий погон мандрує світом
І хвилю щастя світові несе.
І у серці кожнім той вогонь палає,
Тим він допоможе, хто перемагає.

Приспів.

Вперед хлопці, вперед дівчата,
Час прийшов перемагати,
Звитяжний настрій, виступи вдалі,
П''ядеслати, пошани, рекорди, медалі.
Ми ж дома лишилися не для відпочинку,
Ми вам гарантуємо гарячу підтримку,
А ви вигравайте, нехай не загине,
Гордість нації, слава України.

Приспів.','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_217993'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_217993','Олімпійський гімн українських вболівальників','Яке гаряче цього року літо,
