INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2184414','Ми сухого плота йдемо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.','Опис гри: Молодь стає парами одна за другою, взявшись за руки і піднісши їх догори. Хто без пари, проходить попід руками через цей "живий коридор", когось із "коридора" забирає з собою і стає з ним у парі попереду. Той, хто лишився сам, вертається назад і знову обирає собі пару, йдучи попід руками... Таким чином "сухий пліт" рухається вперед.','Ми сухого плота йдемо,
Плота йдемо,
Плота йдемо!

Кінця йому не знайдемо,
Не знайдемо,
Не знайдемо!

Ані кінця, ані ладу,
Ані ладу,
Ані ладу!

Вибирай си, котра ззаду,
Котра ззаду,
Котра ззаду!

Треба добре вибирати,
Вибирати,
Вибирати!

Щоб без пари не стояти,
Не стояти,
Не стояти!','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2184414'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2184414','Ми сухого плота йдемо','Ми сухого плота йдемо,
