Гей!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2182798','Південно-Західна залізниця','Музика: Володимир Шинкарук Слова: Володимир Шинкарук. Виконує: Володимир Шинкарук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Не замовкають, шумлять вокзали,
Далекі далі зовуть до себе,
І знов дорога, і знову шпали,
Неначе сходинки в високе небо.

Приспів:
Летить наш потяг, немов жар-птиця,
Крізь темінь ночі назустріч дню,
Південно-Західна залізниця,
Ти крізь долю пролягла мою.

Без відпочинку багато років,
Зима чи осінь, весна чи літо,
І знов дорога, і знов неспокій,
Та ми без цього не можем жити.

Приспів.

Ти крізь долю пролягла мою...

І нам не треба чужої слави,
Бо залізнця і в свято, і в будні,
Вона єднає міста й держави,
Веде з минулого у майбутнє.

Приспів.

Ти крізь долю пролягла мою...
Ти крізь долю пролягла мою...','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2182798'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2182798','Південно-Західна залізниця','Не замовкають, шумлять вокзали,
