INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2181550','Люлька','Українська народна пісня. Виконує: Буря','uk','ukraine_before_1917',NULL,NULL,'Коломийка з наспівів канадських емігрантів','Мелодія - коломийка, подібна до: "Коломия - не помия, Коломия - місто..." Співається під звичайний коломийковий супровід, як мінімум сопілки, краще - сопілка, скрипка та бубен. Я не є великим спеціялістом з гуцульського діялекту, але маю такі поради: * - сі, ся, сє у гуцулів вимовляється ближче до ші, шя, шє, у багатьох селах "ся" часто переходить у "сі" (з дотриманням шиплячої "с" ** - "я" у цих складах вимовляється ближче до "є".','Із вечора аж до рана люлька ся* курила
Впала з п''єца на підлогу- люлічка ся* збила.

Я поїхав в Коломию люльку купувати,
Така файненька, червона, - ніяк** вторгувати.

А Марічка тота була, яка** продавала
А я її попросив. - вона вторгувала.

Як** зачєла торгувати, писочком крутити,
Я їй мусив за десєтку* горівки купити.

А Марічка дурна була, - горівков ся* впила,
Цілий тиждень по подвір''ю як дурна гонила.

Вона така п''яна була, комусь* дала та й забула,
Тепер ходить і шукає, - кому дала та й не знає','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2181550'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2181550','Люлька','Із вечора аж до рана люлька ся* курила
Впала з п''єца на підлогу- люлічка ся* збила.

Я поїхав в Коломию люльку купувати,
Така файненька, червона, - ніяк** вторгувати.

А Марічка тота була, яка** продавала
А я її попросив. - вона вторгувала.

Як** зачєла торгувати, писочком крутити,
Я їй мусив за десєтку* горівки купити.

А Марічка дурна була, - горівков ся* впила,
Цілий тиждень по подвір''ю як дурна гонила.

Вона така п''яна була, комусь* дала та й забула,
Тепер ходить і шукає, - кому дала та й не знає');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2183522','Поїхав козак на чужину','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Єфросинія Душна, Андрій Душний. Бандуро, дзвени, не стихай! /Збірка творів для учнів початкових мистецьких навчальних закладів. – Львів: ТеРус, 2005. – 44 с.',NULL,'Поїхав козак на чужину
На свому гнідому коні,
Покинув, покинув свою Україну
І свій рідний батьківський двір.

Покинув дівчину кохану,
Що в неї серденько болить,
І жде вона кожного вечора й ранку,
Що милий її прилетить.

Приїхав козак на подвір''я
І скочив з гнідого коня. -
Немає, немає моєї дівчини,
Болить моє серце, душа.','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2183522'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2183522','Поїхав козак на чужину','Поїхав козак на чужину
На свому гнідому коні,
Покинув, покинув свою Україну
І свій рідний батьківський двір.

Покинув дівчину кохану,
Що в неї серденько болить,
І жде вона кожного вечора й ранку,
Що милий її прилетить.

Приїхав козак на подвір''я
І скочив з гнідого коня. -
Немає, немає моєї дівчини,
Болить моє серце, душа.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218165','Де ти бродиш моя доле','Музика: Марко Кропивницький Слова: Степан Писаревський. Виконує: Ольга Богомолець, Василь Триліс, Павло Кармалюк, М. Фокін','uk','ukraine_1991',NULL,NULL,NULL,'Романс із опери "Вій" Марка Кропивницького за Миколою Гоголем. Аранжування Владислава Заремби.','Де ти бродиш, моя доле?
Не докличусь я тебе!
Досі б можна дике поле
Пригорнути до себе!
Все питаю, все шукаю,
Аж серденько ізв''ялив...

Чи на морі між купцями
Лічиш з краму бариші,
Чи в хоромах з панянками
Ти регочешся вночі?
Чи при місяці, без сонця,
Чешеш кучері дівкам,
Чи на небі із віконця
Сучиш дулі біднякам?

Чи у полі при долині
Диким маком ти цвітеш,
Чи у лузі на калині
Ти зозулею куєш?
Ой змилуйся моя нене,
Та край мене хоч присядь,
Хоч постій ти біля мене,
То й тому я буду рад!','["pisni.org.ua", "cat:philosophic", "cat:romansy", "Філософські пісні", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_218165'), datetime('now')),datetime('now'));
