INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_218165_l1','pisniua_218165','YouTube','https://www.youtube.com/watch?v=qqnYqlvKXi8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2184498','Катерина і Василь','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.','Опис гри: Хлопчики й дівчатка, розділившись попарно, беруться за руки і кружляють у такт пісні спочатку в один бік (чотири такти за годинниковою стрілкою, починаючи з правої ноги), а потім у другий (чотири такти проти годинникової стрілки, починаючи з лівої ноги). На словах "Ой, Василю... " тричі погрожують один одному вказівним пальцем правої руки, а на слові "...Василю" — вказівним пальцем лівої руки (навхрест). На словах "не їж" і "мого" по черзі злегка вдаряють один одного долоня в долоню — правою, потім лівою. А на слові "киселю " тричі притупують ногами, починаючи з лівої.','Катерина і Василь
Посварились за кисіль:
Ой, Василю, Василю,
Не їж мого киселю!
Ой, Василю, Василечку,
Не їж мого киселечку!

А Оксана і Тиміш
Посварились за куліш:
Ой, Тимоше, Тимошу,
Не їж мого кулешу!
Ой, Тимоше, Тимошечку,
Не їж мого кулешечку!

А Марина та Дем''ян
Посварились за бур''ян:
Ой, Дем''яне, Дем''яну,
Не рви мого бур''яну!
Ой, Дем''яне, Дем''яночку,
Не рви мого бур''яночку!','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2184498'), datetime('now')),datetime('now'));
