INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218461','Весна Наша Весна що Ти нам принесла (1)','Українська народна пісня. Виконує: Надія Зяблюк','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Воскресна - Жартівлива. Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Вже Весна воскресла. Летів Шулячище та через Селище. Статеві, вікові та станові гурти. Самогуртування народу в статеві, станові та вікові гурти лежало безперечно в засадах Старовіцького суспільного світогляду Українського народу, а не було ділом припадку. А що воно перейшло було в суспільну норму, свідчать про це Колядки й Щедрівки, які згадують часто про установу Трьох Сел на Україні і дають докази, що були вони не тільки в Старинні часи, але перетривали до новішої доби. Були це окремі села: Старих людей, Молодців (Парубків) і Дівчат. (Самогуртування: У праці Кс. Сосенка вжито "гуртуванняся", що відповідало б "самоорганізації" в сучасній науковій термінології. Самоорганізація як явище є предметом вивчення окремої сучасної науки — синергетики. Доречно говорити про етнологічну синергетику.) Є таких Колядок і Щедрівок про Три Села більше, та з образцями не однакової культурної доби, що якраз свідчить про колишню довготривалість тої суспільної установи. Схильність до народних чи племінних зборів. Оця дуже цікава Староукраїнська суспільна проблема варта всестороннього опрацювання; відкладемо її до ширшого розглянення при розділі про Щедрівки, бо найбільше на цю тему є Щедрівок; а тут рад би я дати вибрані приклади з Колядок і Щедрівок, щоби удовіднити, що тенденція народних чи племінних зборів, а вслід за тим і свято всенародного Збору на Україні, — яке треба розширити, окрім збору Різдвяного й Богоявлінського, і на Великодній, — має в основі дуже поважні етно-культурні задатки — і від них зачинаючи, треба би ці Свята поясняти. Бо — і зараз Українські всенародні святочні (церковні) збори, приміром Різдвяні, Йорданські й ін., мають давнє етно-суспільне забарвлення: загального збору поодиноких статевих гуртів і вікових відділів віку. Хто не довіряє, нехай придивиться до збору народу в великі свята по всіх церквах на Україні: нарід стоїть там самочинно поділений: по правій руці — на переді діти-хлопчики, за ними підростки, відтак старші господарі, за ними молодші господарі, а далі гурт парубоцтва; по лівій руці — на переді дівчатка-недолітки, за ними дівоцтво, за дівоцтвом бабусі (звичайно біля лавок), а в "бабинці" матусі та молодиці з маленькими діточками на руках. Такий Старовіцький лад є без виїмку по всій Україні, і нема цього у ніяких інших, т. зв. Індоєвропейських, народів, що окружають Українців. Щось подібного знаходимо у Жидів в їх Святинях, де чоловіки в часі богослужень займають долішню наву Святині, а жіноцтво перебуває на горішніх її поверхах. Гуртовий статевий поділ є і в Турецько-Арабських Святинях. Праісторичність і містика самогуртування. Майже всі Колядки і Щедрівки, інші пісні на тему вікових і статевих гуртів відзначуються Місячно-мітольоґічною символікою, що є характеристикою старинности тих Пісень тай цієї теми. Через оцю мітольоґічну закраску набирає і сама тема мітичного значення, що однакож не відбирає їй значення реальної традиції, а за те окружує її німбом Святости і творить з неї окремий об''єкт шанування й скріплює її повагу. Але все те вказує, що традиції ці не історичні, але праісторичні. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень: Українське Свято Відродження Світа. (Вибір Пісень) Що означає "Свята Вечеря"? Частина 2. Традиції самогуртування: Cвятий Збір. Прадідна доба. Ідеальні Села. Статеві громади. Стежки до листків про Українські традиції.','Співається за зразком:

Весна Наша Весна що Ти нам принесла
що Ти нам принесла
А я Вам принесла Літечко Теплечко
Літечко Теплечко

Літечко Теплечко Червоне Яєчко
Червоне Яєчко й уже недалечко
Летів Шулячище та через Селище
Просив у Дівочок по Парі Яєчок
А Вони не дали Шуляком прозвали
Бодай Вам Дівочки з кропиви Віночки
З кропиви Віночки з трави Китайочки
З трави Китайочки з мачули Сорочки','["pisni.org.ua", "cat:suspilno-politychni", "cat:vesnyanky-hayivky", "Суспільно-політичні пісні", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_218461'), datetime('now')),datetime('now'));
