INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185096','Да пішли дівки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Да пішли дівки      | (2)
Да й у гай по квітки,
Іване, Йване, гу!

Да прийшлось дівкам | (2)
Да Дунай брести,
Іване, Йване, гу!

А сиротині          | (2)
Да й перед вести,
Іване, Йване, гу!

Да й усі дівки      | (2)
Дунай перебрели,
Іване, Йване, гу!

А сиротина          | (2)
Да й утонула,
Іване, Йване, гу!

Да пішли слухи      | (2)
Й аж до мачухи,
Іване, Йване, гу!

Да не жаль мені     | (2)
Да сиротини,
Іване, Йване, гу!

