INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218591','Весна Наша Весна що Ти нам принесла (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави. Розспів: Вес-на На-ша Вес-на що Ти нам при-нес-ла |(2) Вже Весна воскресла. А я вам принесла Дівоцькую зброю.','Весна Наша Весна
