INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185313','Котився снопочок по полю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Котився снопочок        |
По полю.                | (2)

Просився в женчиків     |
Додому.                 | (2)

Візьміть мене, женчики, |
З собою.                | (2)

Занесіте мене           |
В стодолу.              | (2)

Я в стодолоньці         |
Погощу.                 | (2)

Та й на нивоньку        |
Знов піду!              | (2)','["pisni.org.ua", "cat:obzhynkovi", "cat:volynski", "Обжинкові пісні", "Пісні з Волині"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185313'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185313','Котився снопочок по полю','Котився снопочок        |
