INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185267','Ой, чиє то поле заспівало стоя?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой, чиє то поле
Заспівало стоя?
Заспівало нам,
Хорошим женцям. Гу!

Іванове поле
Заспівало стоя.
Ми його дожнем,
У копи складем. Гу!

А чужії женці
Та все шолудивці -
Жита не пожали,
Серпи поламали. Гу!

А нашії женці
Та все чорнобривці -
Житечко дожали,
В снопи пов''язали. Гу!','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185267'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185267','Ой, чиє то поле заспівало стоя?','Ой, чиє то поле
Заспівало стоя?
Заспівало нам,
Хорошим женцям. Гу!

Іванове поле
Заспівало стоя.
Ми його дожнем,
У копи складем. Гу!

А чужії женці
Та все шолудивці -
Жита не пожали,
Серпи поламали. Гу!

А нашії женці
Та все чорнобривці -
Житечко дожали,
В снопи пов''язали. Гу!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185495','Колискова','(Спи, засни, моя дитино, спи, моє маля...). Музика: Роман Свистун Слова: Андрій Малишко','uk','ukraine_before_1917',NULL,NULL,'Збірка пісень "Край ромашковий"',NULL,'Спи, засни, моя дитино, спи, моє маля,
Ніч іде в гаї, долини, трави нахиля.
Хай тобі ця ні насниться, що в огнях сія.
Будеш завтра в світ дивитися, зіронько моя!

Перша ніч твоя почата
В співах солов''я,
Дай же мамі рученята,
Зіронько моя.

Посміхнись до мене, синку,
І зрадію я,
Не хвилину і не днину -
Я навік твоя.

Сплять ліси, поля, криниці,
Шепіт ручая.
Ти відкрий, відкрий очиці,
Юносте моя.

Підеш ти по Україні,
Де життя буя.
Виростай, моя дитино,
Зіронько моя!','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185495'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185495','Колискова','Спи, засни, моя дитино, спи, моє маля,
Ніч іде в гаї, долини, трави нахиля.
Хай тобі ця ні насниться, що в огнях сія.
Будеш завтра в світ дивитися, зіронько моя!

Перша ніч твоя почата
В співах солов''я,
Дай же мамі рученята,
Зіронько моя.

Посміхнись до мене, синку,
І зрадію я,
Не хвилину і не днину -
Я навік твоя.

Сплять ліси, поля, криниці,
Шепіт ручая.
Ти відкрий, відкрий очиці,
Юносте моя.

Підеш ти по Україні,
Де життя буя.
Виростай, моя дитино,
Зіронько моя!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185192','Зробим Купайло','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Зробим Купайло
До місяця,
Нехай всі хлопці
Повісяться.

Зробим купайло
До зіроньки,
Нехай гуляють
Всі дівоньки!
* * *
Ой, на городі
Бур''ян поріс,
Забрав чорт хлопців,
Тай в ліс поніс!

Ой, носив, носив -
Не виносив,
Взяв на гілляку
Та й вивісив!
* * *
Ой, на Купала
Вогонь горить,
А нашим хлопцям
Живіт болить.

Ой, нехай болить,
Нехай знають,
Нехай Купайла
Не займають!','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185192'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185192','Зробим Купайло','Зробим Купайло
До місяця,
Нехай всі хлопці
Повісяться.

Зробим купайло
До зіроньки,
Нехай гуляють
Всі дівоньки!
* * *
Ой, на городі
Бур''ян поріс,
Забрав чорт хлопців,
Тай в ліс поніс!

Ой, носив, носив -
Не виносив,
Взяв на гілляку
Та й вивісив!
* * *
Ой, на Купала
Вогонь горить,
