Не займають!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2186226','Друга весільна пісня','Музика: Мирослав Скорик Слова: народні. Виконує: Ніна Матвієнко, Вікторія Лук''янець, Тарас Ященко, Оксана Муха','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Шуміла ліщина,
Як ся розвивала,
Плакала дівчина,
Як ся віддавала.

Що другі дівчата
Ще будуть гуляли,
Мені молоденькій
Рученьки зв''язали.

Марусю, сестричко,
Як тобі здається,
Твій братчик на войні,
А ти віддаєшся?..

Твій братчик на войні
Кровцю проливає,
В тебе весілечко -
Він того не знає.

Шуміла ліщина,
Як ся розвивала,
Плакала дівчина,
Як ся віддавала.

Що другі дівчата
Ще будуть гуляли,
Мені молоденькій
Рученьки зв''язали.

Шуміла ліщина...','["pisni.org.ua", "cat:nostalgia", "cat:vesilni", "Пісні з ностальгічними мотивами", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2186226'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2186226','Друга весільна пісня','Шуміла ліщина,
