INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185158','Ой, за городом річка тече','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой, за городом
Річка тече,
А там Тетяна
Млинці пече.

Ой, там Василько
Воду носить,
В свої Тетяни
Млинця просить.

Ой, дай, Тетяно,
Хоч млинчика -
Привезу тобі
Гостинчика!

Ой, дай, Тетяно,
Хоч одного -
Привезу тобі
Дорогого!','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185158'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185158','Ой, за городом річка тече','Ой, за городом
Річка тече,
