INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2186990','Гой питалася княжа корона','Музика: Г. Гаврилець Слова: народні. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гой питалася княжа корона,
Чи є в державі такая жона,
Такая жона, як наша панна,      |
Як наша панна - Вельможна Галя! | (2)

Ой, а в її дворі щодень собори,
Державовладдя три ради радять.
Ой, перша рада за виногради:    |
Де їх садити, вина мостити?     | (2)

Другу радочку - за колядочку:
Чим їх приймати, обдарувати?
А третю раду - за її чада,      |
Як їх сдружати й навчати.       | (2)

Синів оженю з царівночками,
А дочок віддам державним панам,
А дочок віддам державним панам, |
А на сім слові будьмо здорові!  | (2)

Будьмо здорові! Будьмо здорові!','["pisni.org.ua", "cat:kolyadky", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2186990'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2186990','Гой питалася княжа корона','Гой питалася княжа корона,
Чи є в державі такая жона,
Такая жона, як наша панна,      |
