INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2186212','Перша весільна пісня','Музика: Мирослав Скорик Слова: народні. Виконує: Ніна Матвієнко, Вікторія Лук''янець, Тарас Ященко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, летять галочки
Та й у три рядочки,
Зозуленька попереду.

Ой, усі галочки         |
По лугах сіли,          |
Зозуленька - на калині. | (2)

Ой, усі галочки
Защебетали,
Зозуленька закувала.

Ой, ідуть дружечки
Та й у три рядочки,
Молоденька попереду.

Ой, усі дружечки        |
По лавах сіли,          |
Молоденька - на посаді. | (2)

Ой, усі дружечки
Заспівали,
Молоденька заплакала.','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2186212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2186212','Перша весільна пісня','Ой, летять галочки
Та й у три рядочки,
Зозуленька попереду.

Ой, усі галочки         |
По лугах сіли,          |
Зозуленька - на калині. | (2)

Ой, усі галочки
Защебетали,
Зозуленька закувала.

Ой, ідуть дружечки
Та й у три рядочки,
Молоденька попереду.

Ой, усі дружечки        |
По лавах сіли,          |
Молоденька - на посаді. | (2)

Ой, усі дружечки
Заспівали,
Молоденька заплакала.');
