INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2188798','Хай землю виорять гармати','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Ірена Дорончук',NULL,'Хай землю виорять гармати,
Під волю вироблять посів
Побачите в жнива дівчата
Нас - партизанів косарів.

На грудях кулеметна стрічка,
В руках граната і наган,
Недаром тобі дівчино сниться
Твій милий в УПА-партизан.

Твій милий десь далеко в лісі
Лежить в терновому вінку,
Згадай його хоч раз у пісні
У тихий вечір у садку.

А інший милий запитає:
Про кого пісня ця сумна?
Не скажеш, хай і він не знає
Цю тайну знай лиш ти одна.','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2188798'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2188798','Хай землю виорять гармати','Хай землю виорять гармати,
