INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2188010','Балада про повстанця','Слова: Євгенія Лещук. Виконує: Світозари','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ой ударила куля
Повстанця в чоло -
Сколихнулося небо,
Сколихнулось село.
І у полі широкім       |
Поміж квітів і трав,   |
Наче ясен високий,     |
Повстанець упав.       | 2

Як побачив це лихо
Вітерець степовий,
Запитав його тихо:
- Чи ти, друже живий?
Та стрілець тому вітру |
Жодних слів не повів,  |
Тільки маком червоним  |
Серед поля зацвів.     | 2

- Ой, скажи ще, вояче,
Чий ти муж, чий ти син?
Чому нині так плаче
За тобою Волинь?..
Та стрілець тому вітру
Жодних слів не сказав,
Тільки маком червоним
Серед поля зітхав.
Вітер знову питався:
- Чи у тебе є брат?
Звідкіля ти добрався
До високих Карпат?
Та стрілець тому вітру  |
Жодних слів не повів,   |
Тільки маком червоним   |
По Вкраїні зацвів...    | 2','["pisni.org.ua", "cat:viyskovi", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2188010'), datetime('now')),datetime('now'));
