Мене вислухай, вислухай...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2189212','Прощавання та розлуки','Виконує: Берники','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приємні хвилини так швидко минають -
І не повернути нам спільності мить,
І теплі прощання слова
Сказати прийшла вже пора,
У кожного буде дорога своя!

Приспів:
Прощавання та розлуки -
Невід''ємні є в житті.
Та надія не згасає -
Будуть зустрічі нові!

Хай з кожним із вас Бог і далі крокує,
В любові своїй захистить, збереже,
Щоб з Ним було ваше життя
І воля Ісуса свята
До зустрічі знову колись привела!

Приспів.

Приємні хвилини так швидко минають -
І не повернути нам спільності мить,
Якщо не зустрінемось тут
Ми - вірні, хвилини прийдуть -
До неба дороги усіх приведуть!

Приспів. (2)

Будуть зустрічі нові!
Будуть зустрічі нові!','["pisni.org.ua", "cat:zahalni-cinnosti", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2189212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2189212','Прощавання та розлуки','Приємні хвилини так швидко минають -
