INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218971','Вже Весна воскресла (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... РОЗСПІВ: Вже Вес-на вос-кре-е-ес-ла Що Ти на-ам при-нес-ла |(2) Вже Весна воскресла. Ой принесла Росу Парубоцьку Красу. Стежки до листків про Українські традиції.','Дівчата взявшись за руки
ідуть по Колу тай співають :

Вже Весна воскресла
Що ти нам принесла |(2)

Ой принесла Росу
Парубоцьку Красу |(2)

Парубоцька Краса
В болоті мочена |(2)

В Болоті мочена
У Калюжі прана |(2)

У Калюжі прана
На Терню сушена |(2)

На Терню сушена
У Хліві схована |(2)

Хлопці також беруться за руки,
беруть у Коло Дівчат і їм співають:

А Весна Весною
А Дівка Дівкою |(2)

Ходить світом нудить
Спідницею крутить |(2)

Крутить щоб видати
Хочеся віддати |(2)

Дома не сидіти
В Дівках не сивіти |(2)

Покрить головоньку
Не буть Дівчиноньков |(2)

Дранов нагавицев
Стати Молодицев |(2)    Мелодія для 1 і 2 голосу','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_218971'), datetime('now')),datetime('now'));
