INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219124','Чотири рожі','(Чого ж я так нічку марную...). Українська народна пісня. Виконує: Буря','uk','ukraine_before_1917',NULL,NULL,'З пам''яті за давніми емігрантськими аудіозаписами','Вперше почув з емігрантських аудіозаписів канадських українців у 70-х рр. Згодом зрідка чув цю пісню на весіллях на теренах Галичини. * Чув виконання приспіву у варіанті, який не відповідає назві пісні: Рожевая рожа - то признання, Червоная рожа - то любов, А жовтая рожа - то розлука, Що нас розлучила з тобов.','EmH7                  Em
Чого ж я так нічку марную,
Чого ж я так мучу себе,
Коли вже дуже добре знаю,    |
Що милий покинув мене!       | (2)

Приспів:
Рожевая рожа - то признання,
Червоная рожа - то любов,
А жовтая рожа - то розлука,   |
А білая - вкритая сльозов.*   | (2)

Ніколи я того не забуду,
Коли він до мене приходив,
Ніколи я тих слів не забуду,  |
Котрі він до мене говорив.    | (2)

Приспів.

Ніколи я того не забуду,
Коли він до мене повертав,
Він зірвав червоний квіточок  |
І кинув на землю, притоптав.  | (2)

Приспів.

Не плетіть ми вінку з барвінку,
Бо я вже до шлюбу не піду,
А дайте ми жовтую рожу,         |
Бо з милим в розлуці живу.      | (2)

Приспів.

Чого ж я так нічку марную,
Чого ж я так мучу себе,

Коли вже дуже добре знаю,  |
Що милий покинув мене!     | (2)','["pisni.org.ua", "cat:43", "cat:halycki", "Еміґрантські пісні", "Пісні з Галичини"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_219124'), datetime('now')),datetime('now'));
