INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219111','Пісня мамонтеняти','(Хай мама знайде). Музика: В. Шаїнський Слова: Д. Непомнящий','uk','ukraine_1991',NULL,NULL,NULL,NULL,'По синьому морі на хвилі морській
