INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2191328','Пісня про нашу пісню','Музика: Геннадій Желуденко Слова: Геннадій Желуденко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Пісне українська, ясна наша зоре,
Ти ж одвіку з нами в радості і в горі!
Тож після святого слова Отченаша
Шану хай найбільшу має пісня наша
У-кра-ї-нська!
Так співаймо ж, браття, так співаймо ж, сестри,
Пісні українській не дамо померти!
Зразу за Отченашем
Пісню шануймо нашу!

Пісне українська, ти - дарунок Божий,
Бо від нас незгоду відвернути можеш
Тим, що нас єднаєш, а не половиниш,
Тим, що твоя мова - лиш одна-єдина,
У-кра-ї-нська!
Так співаймо ж, браття, так співаймо ж, сестри,
Пісні українській не дамо померти!
Пісня людей збирає,
В нарід один єднає!

Пісне українська, будь же нездоланна,
Ти ж бо нашій мові прихисток останній!..
Тож збагнем назавжди, поки не запізно -
Доти буде мова, доки буде пісня
У-кра-ї-нська!
Так співаймо ж, браття, так співаймо ж, сестри,
Пісні українській не дамо померти!
Житиме пісні слово -
Житиме й наша мова!

В пісні українській слів не забуваймо,
Їм дітей і внуків змалечку навчаймо!..
З піснею ніяка сила нас не зборе,
Ще ж якщо й співати дружно, вкупі, хором
У-кра-ї-нським!
Так співаймо ж, браття, так співаймо ж, сестри,
Пісні українській не дамо померти!
Нас, якщо будем хором,
Ніхто й ніщо не зборе!','["pisni.org.ua", "cat:pisni", "Пісні про пісню"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2191328'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2191328','Пісня про нашу пісню','Пісне українська, ясна наша зоре,
