INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2192614','Старий рік минає','Українська народна пісня. Виконує: Дармограй','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Віншування:
Ми твого двора не минаємо,
Щедрий вечір! Добрий вечір!
Твоє обійстя звеличаємо,
Вставай з постелі, одчиняй двері,
Одчиняй сіни, щоб бджоли сиділи,
Застеляй столи все тисовії,
Клади калачі з ярої пшениці,
В решето овса, на верх - ковбаса!

Старий рік минає,
Старий рік минає, Новий наступає,        |
Новий наступає!                          | (2)

Іди, старий роче,
Іди, старий роче, ми тебе не хочем.      |
Ми тебе не хочем!                        | (2)

Нам Новий Рік кращий,
Нам Новий Рік кращий, принесе нам щастя, |
Принесе нам щастя!                       | (2)

А ви, люди, чуйте,
А ви, люди, чуйте, коляду рихтуйте,      |
Коляду рихтуйте!                         | (2)

Голубців мищину
Голубців мищину, медочку фляшчину,       |
Медочку фляшчину!                        | (2)

А для тої втіхи,
А для тої втіхи, дайте нам горіхів,      |
Дайте нам горіхів!                       | (2)

Вам за дари тії,
Вам за дари тії - літа щасливії,         |
Літа щасливії!                           | (2)','["pisni.org.ua", "cat:kolyadky", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2192614'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2192614','Старий рік минає','Віншування:
Ми твого двора не минаємо,
