INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_21899','Горянка','Музика: Левко Дутковський Слова: Микола Леонтюк, Сергій Борисенко. Виконує: Назарій Яремчук, Василь Зінкевич, Смерічка','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Бери мене, сивий орле, на широкі крила,
Занеси мене у гори, де сумує мила.
Де срібляться рідні звори і зоріють ранки,
Занеси мене у гори, в гори до горянки

Приспів:
Поміж буки, поміж граби Черемош несе дараби.
Здійми, орле, крила, широкі вітрила.
Пісні в серці принесу я, що славлять Карпати,
Заспіваю і коханій не дам сумувати.

Віднеси мене в Карпати, василькові плаї,
Там, де вітер Верховині коси розплітає.
Віднеси, бо серцем чую, для її чекання
Милій пісню подарую, пісню про кохання.

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_21899'), datetime('now')),datetime('now'));
