INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2192461','Під віконцем горличка співала','Музика: Зоя Красуляк Слова: Зоя Красуляк. Виконує: Р. Тулякова','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Під віконцем горличка співала,
Пана господаря викликала:
Де ж це пан-господар, хай виходить,
Нехай йому нива гарно родить!
Де ж це пан-господар, хай виходить,
Нехай йому нива гарно родить!

Під віконцем горличка співала,
Господиню із Різдвом вітала:
Де ж це господиня, нехай вийде,
Їй хай щастя й радість в хату прийде!
Де ж це господиня, нехай вийде,
Їй хай щастя й радість в хату прийде!

Під віконцем горличка співала,
Всій родині щастя бажала:
Ой, пошли ж вам Боже срібла й злата,
Щоб були веселі ви й багаті!
Ой, пошли ж вам Боже срібла й злата,
Щоб були веселі ви й багаті!','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2192461'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2192461','Під віконцем горличка співала','Під віконцем горличка співала,
Пана господаря викликала:
