INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2193717','Ніч над Вифлеємом','Музика: Марта Лозинська Слова: Марта Лозинська','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ніч над Вифлеємом,
Зорі в небі сяють,
Сон над усіма витає.
А в бідній стаєнці,          |
Де ніхто не знає,            |
Дитя Боже ся рождає.         | (2)

Там Пречиста Діва
Сина породила
І в яселках Його сповила.
А на небі зірка              |
Ясно засвітила,              |
Новину усім сповістила.      | (2)

Ангели співають,
Бога величають,
Славу на весь світ голосять.
А волик з ослятком           |
Над малим Дитятком           |
На колінцях тихо стоять.     | (2)

Пастушки з царями
Йдуть в вертеп з дарами,
Поспішає кожен, хто не спить.
А Марія-Мати                 |
Для свого Дитяти             |
Постіленьку з сіна лагодить. | (2)

Спи, Ісусе милий,
Набирайся сили,
Щоб здолати все люте зло.
Коли будеш спати -           |
В кожній нашій хаті          |
Запанує мир і добро.         | (2)

Вся земля співає:
"Христос ся рождає!"
Божий дзвін лунає по церквах.
Українські люди,             |
Христос з нами буде,         |
Хай луна колядка в небесах!  | (2)','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2193717'), datetime('now')),datetime('now'));
