INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2192165','Колядка','Музика: Михайло Герц Слова: Іван Окаль','uk','ukraine_before_1917',NULL,NULL,'нова пісня','У приспіві з другого куплету може співати група дітей.','Ісусик маленький не спить не дрімає
