INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2193420','Галичина (Над чарівним куточком землі..)','Виконує: Богдан Сташків','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Над чарівним куточком землі
Закружляли вже знову лелеки,
Вони довго летіли в імлі,
Щоб вернутись в цей край із далека.

Приспів:
Галичина! Галичина!
Скільки твоїх синів і дочок відлетіло?
Галичина! Галичина!
Твій брат наче мати, що вже посивіла.
Галичина! Галичина!
Ти душа і зоря України.
Галичина! Галичина!
Слава Божа у тобі не згине!

Ярослав Осмомисл Ростиславич
Понад Бугом, Сяном і Дністром
Об''єднав із столицею Галич
Дулібів і тиверців разом.

Приспів.

Хоч віками тебе розділяли,
Грабували і нищили всі,
Але ти не скорилась, не впала,
Відродилась у новій красі.

Приспів.','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2193420'), datetime('now')),datetime('now'));
