INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2194313','Пісня про тата','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Посивіли твої скроні,
Аж душа моя болить.
Нахилю в твої долоні
Голівоньку, хоч на мить.
Засіяє біла хата,
Засміються рушники,
Вийде тато зустрічати,
Як у юнії роки.

Приспів:
По вербовій кладочці
У дитинство повернусь,
Із долоней татових
Чистої води нап''юсь -
І запахне м''ятою
Рідний батьківський поріг.
Тату, тату, таточку,
Тільки не старій.

Я вдивлюсь в твоє обличчя,
В очі лагідні твої,
І, здається, там курличуть
Беззахисні журавлі.
Посідаємо близенько
Де любисточок росте,
Тату, таточку рідненький,
В тебе серце золоте.

Приспів. (3)','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2194313'), datetime('now')),datetime('now'));
