INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219293','Із янголом на плечі *','Музика: Тарас Чубай Слова: Іван Малкович. Виконує: Тарас Чубай, Плач Єремії','uk','ukraine_1991',NULL,'1992','текст: http://poetyka.uazone.net/malkovych/jangol01.html (Валерій Корнєєв, з дозволу автора); аудіо-CD: Тарас Чубай. Світло і сповідь. 2003','Вірш датовано: 30-31 січня 1992 Акорд A* - [0 0 2 2 x 0] або [0 0 2 2 0 0] Демо-аудіо (mp3): http://www.umka.com.ua/sound/chubaj01/chubaj01-01.mp3 Підбір акордів: bohdanko@epost.com.ua','Вступ: Em

