INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219573','Чорнобильська зона','Музика: Тарас Петриненко Слова: Тарас Петриненко. Виконує: Тарас Петриненко, Гроно','uk','ukr_ssr_1919_1991',NULL,'1986','Гуру','Пісня про Чорнобильську катастрофу, яка сталася 26 квітня 1986 року на Чорнобильській АЕС. Це пісня з аудіо-альбому "Я професійний раб" Тараса Петриненка. Підбір акордів: Гуру','Em
Все зійшло нанівець,
C
