INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2196414','Та косив батько, косив я','Українська народна пісня. Виконує: Древо','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Та косив батько, косив я,
Та й викосили солов''я
Соловей у саду тьох да тьох.
Канареєчка...

Приспів:
Роман косить, Гапка в''яже,
Катерина загріба,
Грицько воли напува,
Ганна воду витяга.
Ой, мамо, люблю Гриця.
Гриць на конику вертиться.
В Гриця шапка до лиця,
Люблю Гриця молодця.

Та прийди, Грицю, у неділю,
Та дам сорочку же тонку й білу
Соловей у саду тьох да тьох.
Канареєчка...

Приспів.

Да прийди, Грицю, в понеділок,
Да підем разом по барвінок.
Соловей у саду тьох да тьох.
Канареєчка...

Приспів.

Да прийди, Грицю, у вівторок,
Тай зв''яжемо снопів сорок
Соловей у саду тьох да тьох.
Канареєчка...

Приспів','["pisni.org.ua", "cat:lirychni", "cat:narodni", "Пісні про кохання, ліричні", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2196414'), datetime('now')),datetime('now'));
